+      : `Your account is being monitored according to our standard procedures. No escalation is required at this time. Please reach out to your account team with any questions.`;
+
+    await client.query(
+      `INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)`,
+      [requestId, accountId, customerMsg]
+    );
+
+    // Persist audit_events (customer-visible)
+    await client.query(
+      `INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible)
+       VALUES ($1, $2, $3, $4, $5)`,
+      [
+        requestId,
+        accountId,
+        qualifies ? "Escalation workflow initiated" : "Account monitoring check completed",
+        now,
